  <script>
  (() => {
    const helper = window.TavernHelper || window.parent?.TavernHelper || window;
    const root = document.querySelector('.ellia-suggestion-save-box');
    if (!root || !helper?.getVariables || !helper?.replaceVariables) return;

    const COST = 100;
    const SUGGESTION_MARKER = '[viva la vida]';
    const rawSuggestion = String(root.querySelector('.ellia-suggestion-save-text')?.textContent || '').replace(/\r/g, '');
    const markerIndex = rawSuggestion.indexOf(SUGGESTION_MARKER);
    const tone = (markerIndex === -1 ? '' : rawSuggestion.slice(markerIndex + SUGGESTION_MARKER.length))
      .replace(/[\r\n<>]/g, ' ')
      .replace(/\s+/g, ' ')
      .trim()
      .slice(0, 80);

    const fpPaths = [
      'stat_data.主角.FP',
      'stat_data.主角.fp',
      'stat_data.主角.命运点数',
      'stat_data.主角.命运点数(FP)',
      'stat_data.主角.命运点数fp',
      'stat_data.FP',
      'stat_data.fp',
      'stat_data.命运点数',
      '主角.FP',
      '主角.fp',
      '主角.命运点数',
      'FP',
      'fp',
      '命运点数',
    ];

    const button = root.querySelector('.ellia-suggestion-save-button');
    const status = root.querySelector('.ellia-suggestion-save-status');
    const text = root.querySelector('.ellia-suggestion-save-text');
    const setStatus = (message, state = '') => {
      if (status) status.textContent = message;
      root.classList.toggle('is-error', state === 'error');
      root.classList.toggle('is-saved', state === 'saved');
    };
    if (text) text.textContent = tone || rawSuggestion.trim();

    if (markerIndex === -1) {
      if (button) button.disabled = true;
      setStatus(`未检测到 ${SUGGESTION_MARKER}。`, 'error');
    }

    const getPath = (obj, path) =>
      path.split('.').reduce((value, key) => (value && typeof value === 'object' ? value[key] : undefined), obj);

    const setPath = (obj, path, value) => {
      const parts = path.split('.');
      let current = obj;
      for (const key of parts.slice(0, -1)) {
        if (!current[key] || typeof current[key] !== 'object') current[key] = {};
        current = current[key];
      }
      current[parts.at(-1)] = value;
    };

    const parseFp = value => {
      if (typeof value === 'number' && Number.isFinite(value)) return value;
      if (typeof value === 'string') {
        const match = value.match(/-?\d+(?:\.\d+)?/);
        if (match) return Number(match[0]);
      }
      return null;
    };

    const findFp = vars => {
      for (const path of fpPaths) {
        const value = parseFp(getPath(vars, path));
        if (value !== null && Number.isFinite(value)) return { path, value };
      }
      return null;
    };

    const getPromptInput = () => {
      const doc = window.parent?.document || document;
      const selectors = [
        '#send_textarea',
        'textarea#send_textarea',
        'textarea[name="send_textarea"]',
        '#message_textarea',
        'textarea',
        '[contenteditable="true"]',
      ];
      for (const selector of selectors) {
        const element = doc.querySelector(selector);
        if (element && element.nodeType === 1) {
          return element;
        }
      }
      return null;
    };

    const insertIntoPromptInput = value => {
      const input = getPromptInput();
      if (!input) return false;

      const tagName = String(input.tagName || '').toLowerCase();
      if (tagName === 'textarea' || tagName === 'input') {
        const current = input.value.trimEnd();
        input.value = current ? `${current}\n${value}` : value;
      } else {
        const current = (input.textContent || '').trimEnd();
        input.textContent = current ? `${current}\n${value}` : value;
      }

      input.dispatchEvent(new Event('input', { bubbles: true }));
      input.dispatchEvent(new Event('change', { bubbles: true }));
      input.focus();
      return true;
    };

    const buildReminderText = value => {
      const safeTone = value.replace(/"/g, "'");
      return `[Reminder_Rote Blume] 用户已設定自定义故事风格: "${safeTone}"`;
    };

    button?.addEventListener('click', () => {
      if (!tone) {
        setStatus(markerIndex === -1 ? `未检测到 ${SUGGESTION_MARKER}。` : '候选内容为空。', 'error');
        return;
      }

      const messageVars = helper.getVariables({ type: 'message', message_id: 'latest' }) || {};
      const fp = findFp(messageVars);
      if (!fp) {
        setStatus('未找到 FP 变量。', 'error');
        return;
      }
      if (fp.value < COST) {
        setStatus(`FP 不足：当前 ${fp.value}，需要 ${COST}。`, 'error');
        return;
      }

      setPath(messageVars, fp.path, fp.value - COST);
      helper.replaceVariables(messageVars, { type: 'message', message_id: 'latest' });

      const chatVars = helper.getVariables({ type: 'chat' }) || {};
      setPath(chatVars, 'dialog_beauty.story.skill4', 'CUSTOM');
      setPath(chatVars, 'dialog_beauty.story.skill4Custom', tone);
      setPath(chatVars, 'dialog_beauty.story.skill4Request', false);
      helper.replaceVariables(chatVars, { type: 'chat' });

      button.disabled = true;
      button.textContent = '已保存';
      const inserted = insertIntoPromptInput(buildReminderText(tone));
      setStatus(inserted ? `已保存，剩余 ${fp.value - COST} FP；已写入输入框。` : `已保存，剩余 ${fp.value - COST} FP；但未找到输入框。`, 'saved');
    });
  })();
  </script>
